INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3001100, -416.5, 2.1, 100, 130011, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3001, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 1, 0.0, 2, "ヤマト");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3001101, -416.5, 5.68, 101, 130011, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3001, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 4, 0.0, 2, "ヤマト");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3001102, -416.5, 0.0, 102, 130011, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3001, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 1, 0.0, 1, "ヤマト");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3002100, -416.5, 0.0, 100, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3002, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 1, 0.0, 1, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3002101, -416.5, 0.0, 101, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3002, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 1, 0.0, 1, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3002102, -416.5, 8.53, 102, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3002, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 5, 0.0, 2, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3002103, -416.5, 5.67, 103, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3002, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 7, 0.0, 1, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3002104, -416.5, 0.0, 104, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3002, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 1, 0.0, 1, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3002300, -416.5, 0.0, 300, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3004, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 3, 0.0, 3, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3002400, -416.5, 0.0, 301, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3005, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 7, 0.0, 7, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3003200, -416.5, 4.4, 200, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3003, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 2, 0.0, 1, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3003201, -416.5, 0.0, 201, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3003, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 7, 0.0, 7, "フブキ");
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (3003202, -416.5, 5.6, 202, 130211, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 3003, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 1, 0.0, 2, "フブキ");
